mapper.update:
UPDATE setmeal
name = #{name}, category_id = #{categoryId}, price = #{price}, status = #{status}, description = #{description}, image = #{image}, update_time = #{updateTime}, update_user = #{updateUser}
WHERE id = #{id}

mapper.select:
SELECT s.id, s.category_id AS categoryId, c.name AS categoryName, s.name, s.price, s.status, s.description, s.image, s.update_time AS updateTime FROM setmeal s LEFT JOIN category c ON s.category_id = c.id
AND s.name LIKE CONCAT('%', #{name}, '%')
AND s.category_id = #{categoryId}
AND s.status = #{status}
ORDER BY s.update_time DESC

